--
-- Table structure for table `offers`
--

DROP TABLE IF EXISTS `offers`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `offers` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL,
  `source` enum('france_travail','hellowork','apec','wttj') COLLATE utf8mb4_unicode_ci NOT NULL,
  `source_offer_id` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `source_url` varchar(1000) COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `description_html` mediumtext COLLATE utf8mb4_unicode_ci,
  `contract_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `experience_level` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `remote_policy` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `salary_min` int DEFAULT NULL,
  `salary_max` int DEFAULT NULL,
  `salary_currency` char(3) COLLATE utf8mb4_unicode_ci DEFAULT 'EUR',
  `city` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `department_code` varchar(5) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `lat` decimal(9,6) DEFAULT NULL,
  `lng` decimal(9,6) DEFAULT NULL,
  `posted_at` datetime DEFAULT NULL,
  `scraped_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `fingerprint` char(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_active` tinyint(1) DEFAULT '1',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_offers_source` (`source`,`source_offer_id`),
  KEY `fk_offers_company` (`company_id`),
  KEY `idx_offers_fingerprint` (`fingerprint`),
  KEY `idx_offers_posted` (`posted_at`),
  KEY `idx_offers_city` (`city`),
  KEY `idx_offers_active` (`is_active`),
  FULLTEXT KEY `ft_offers_title_desc` (`title`,`description`),
  CONSTRAINT `fk_offers_company` FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=679 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

